final:
module data_bus_controller(  
    input wire [7:0] data_in1,  
    input wire [7:0] data_in2,  
    input wire obf_control,  
    output reg [7:0] data_out  
);  

always @(*) begin  
    if (obf_control)  
        data_out = data_in1;  
    else  
        data_out = data_in2;  
end  
endmodule
